import{_ as r,o,c as t,a2 as a}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"메뉴 구조 최적화 — Research","description":"","frontmatter":{"title":"메뉴 구조 최적화 — Research","feature_id":"009","date":"2026-06-03T00:00:00.000Z"},"headers":[],"relativePath":"specs/009-nav-menu-restructure/research.md","filePath":"specs/009-nav-menu-restructure/research.md","lastUpdated":null}'),s={name:"specs/009-nav-menu-restructure/research.md"};function i(l,e,n,c,d,h){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="research-메뉴-구조-최적화" tabindex="-1">Research: 메뉴 구조 최적화 <a class="header-anchor" href="#research-메뉴-구조-최적화" aria-label="Permalink to &quot;Research: 메뉴 구조 최적화&quot;">​</a></h1><p>Phase 0 — Technical Context 의 미해결 항목을 해소한다. (모든 IA 결정은 spec 의 2026-06-03 Clarifications 에서 이미 확정됨 — 여기서는 <em>구현 방식</em>의 미지수를 해소한다.)</p><h2 id="r1-생성-수동-사이드바-파일의-경계" tabindex="-1">R1. 생성/수동 사이드바 파일의 경계 <a class="header-anchor" href="#r1-생성-수동-사이드바-파일의-경계" aria-label="Permalink to &quot;R1. 생성/수동 사이드바 파일의 경계&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>config.mts</code>·<code>cowork-sidebar.mts</code>·<code>hermes-sidebar.mts</code> 만 수동 편집한다. <code>blog-archive-sidebar.mts</code>(헤더에 &quot;직접 수정 금지 — 재실행 시 덮어씀&quot;) 와 <code>sidebar.specs.json</code>(sync 스크립트 생성)은 <strong>직접 편집 금지</strong>.</li><li><strong>Rationale</strong>: 생성물을 손으로 고치면 임포터/sync 재실행 시 유실되어 회귀.</li><li><strong>Alternatives</strong>: 전부 수동 편집(거부 — 재생성 시 충돌), 전부 생성기화 (과도 — cowork/hermes 는 1회 추출 후 커밋된 정적 파일).</li></ul><h2 id="r2-vitepress-드롭다운-nav-표현" tabindex="-1">R2. VitePress 드롭다운 nav 표현 <a class="header-anchor" href="#r2-vitepress-드롭다운-nav-표현" aria-label="Permalink to &quot;R2. VitePress 드롭다운 nav 표현&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>themeConfig.nav</code> 항목에 <code>items: [...]</code> 를 주면 드롭다운, <code>link</code> 만 주면 단일 링크. 단일 항목 그룹(홈·GitHub)은 <code>link</code> 로 둔다(FR-3).</li><li><strong>Rationale</strong>: VitePress 1.6 기본 지원. 추가 의존성 불필요.</li><li><strong>Alternatives</strong>: 커스텀 테마 컴포넌트(과도).</li></ul><h2 id="r3-섹션-활성-강조-fr-5" tabindex="-1">R3. 섹션 활성 강조 (FR-5) <a class="header-anchor" href="#r3-섹션-활성-강조-fr-5" aria-label="Permalink to &quot;R3. 섹션 활성 강조 (FR-5)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 각 nav 그룹/항목에 <code>activeMatch</code> 정규식을 부여한다. 예: 개발 기록 → <code>^/(overview|journal|specs)/</code>, 학습 가이드 → <code>^/(skills-talk|cowork)/</code>, 리포트·아카이브 → <code>^/(hermes|blog-archive)/</code>.</li><li><strong>Rationale</strong>: 드롭다운 자식이 특정 페이지 링크라도, <code>activeMatch</code> 로 섹션 전체에서 부모 그룹이 활성 표시되도록 한다.</li><li><strong>Alternatives</strong>: 기본 동작(정확히 일치하는 링크만 활성 — 섹션 강조 불가).</li></ul><h2 id="r4-hermes-사이드바-중복-제거-fr-8-fr-9" tabindex="-1">R4. Hermes 사이드바 중복 제거 (FR-8/FR-9) <a class="header-anchor" href="#r4-hermes-사이드바-중복-제거-fr-8-fr-9" aria-label="Permalink to &quot;R4. Hermes 사이드바 중복 제거 (FR-8/FR-9)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 경로별로 반복되던 &quot;프로젝트 개요&quot; 그룹을 제거하고, 모든 hermes 콘텐츠가 <strong>단일 <code>/hermes/</code> 키</strong>의 통합 사이드바를 공유하도록 재구성한다. 그룹 순서는 개요→분석→시작하기→핵심 기능→재사용성→통합→고급→ 벤치마크→레퍼런스(최근/중요 우선 원칙 반영).</li><li><strong>Rationale</strong>: VitePress 는 현재 경로의 접두사와 일치하는 사이드바 키를 쓴다. 단일 키면 페이지마다 동일·일관 사이드바가 보장(FR-9, 고아 0).</li><li><strong>Alternatives</strong>: 공통 그룹을 const 로 추출해 각 키에서 재사용(중복은 줄지만 키별 정의가 남아 누락 위험 — 거부).</li></ul><h2 id="r5-사이드바-접힘-임계치-적용-fr-7" tabindex="-1">R5. 사이드바 접힘 임계치 적용 (FR-7) <a class="header-anchor" href="#r5-사이드바-접힘-임계치-적용-fr-7" aria-label="Permalink to &quot;R5. 사이드바 접힘 임계치 적용 (FR-7)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 그룹의 <code>items.length &gt; 8</code> 이면 <code>collapsed: true</code>, 그 외는 <code>collapsed</code> 생략(펼침). cowork test &quot;직접 따라해보기&quot;(9), hermes &quot;오피스 업무 시나리오&quot;(14)·&quot;핵심 기능&quot;(9) 등이 접힘 대상.</li><li><strong>Rationale</strong>: spec Clarifications 확정 규칙. 긴 목록의 스크롤 부담 완화.</li><li><strong>Alternatives</strong>: 전부 펼침/전부 접힘(거부 — 일관성·탐색성 균형 실패).</li></ul><h2 id="r6-blog-archive-접힘-규칙-정합-선택" tabindex="-1">R6. Blog Archive 접힘 규칙 정합 (선택) <a class="header-anchor" href="#r6-blog-archive-접힘-규칙-정합-선택" aria-label="Permalink to &quot;R6. Blog Archive 접힘 규칙 정합 (선택)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 아카이브는 생성물이며 현재 전 그룹 <code>collapsed: true</code>. 표준(&gt;8) 과 어긋나는 소형 그룹이 있으나, <strong>대용량 특수 섹션으로 현행 전부 접힘을 허용</strong>한다. 엄격 정합이 필요하면 <code>import-hexo-blog.mjs</code> 의 collapse 로직을 표준으로 바꾸고 재생성(별도 선택 작업).</li><li><strong>Rationale</strong>: 생성 파일 직접 편집 금지(R1). 90여 글 카테고리는 접힘이 오히려 탐색에 유리.</li><li><strong>Alternatives</strong>: 파일 직접 수정(금지), 즉시 임포터 개정(범위 확대 — 선택화).</li></ul><h2 id="r7-url-보존-검증-fr-11" tabindex="-1">R7. URL 보존 검증 (FR-11) <a class="header-anchor" href="#r7-url-보존-검증-fr-11" aria-label="Permalink to &quot;R7. URL 보존 검증 (FR-11)&quot;">​</a></h2><ul><li><strong>Decision</strong>: nav/사이드바는 <strong>링크 대상 경로를 바꾸지 않는다</strong>. 재편 전 nav·사이드바가 가리키던 모든 링크 목록을 수집해, 재편 후에도 동일 경로가 살아있는지 + strict 빌드 통과로 회귀 0 을 확인한다.</li><li><strong>Rationale</strong>: 콘텐츠 파일 이동 없음 → 경로 불변. 빌드가 dead link 검출.</li><li><strong>Alternatives</strong>: 리다이렉트 도입(불필요 — 경로 불변).</li></ul>',16)])])}const m=r(s,[["render",i]]);export{u as __pageData,m as default};
